using namespace std;
int main(){
    long long a,b=0;
    cin>>a;
    for(int i=0;i<a;i++){
        for(int j=0;j<=i;j++){
        	char c='A'+b;
        	if(c>'Z'){
            	c=c-'Z'+'A'-1;
            	b=b-'Z'+'A'-1;
        	}
        	cout<<c;
        	b++;
		}
		cout<<endl;
    }
    return 0;
}
